64	function b64url(bytes: Uint8Array): string {
65	  let s = "";
66	  for (const b of bytes) s += String.fromCharCode(b);
67	  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
