70	async function signMarketifyJwt(
71	  claims: { sub: string; role: "creator" | "lister"; session_id: string },
72	  secret: string,
73	): Promise<string> {
74	  const now = Math.floor(Date.now() / 1000);
75	  const payload = { ...claims, iat: now, exp: now + 300 };
76	  const header = b64url(encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })));
77	  const body = b64url(encoder.encode(JSON.stringify(payload)));
78	  const signingInput = `${header}.${body}`;
79	  const key = await crypto.subtle.importKey(
80	    "raw",
81	    encoder.encode(secret),
82	    { name: "HMAC", hash: "SHA-256" },
83	    false,
84	    ["sign"],
85	  );
86	  const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(signingInput));
87	  return `${signingInput}.${b64url(new Uint8Array(sig))}`;
88	}
